mapper.insert:
		MERGE INTO users u
    	USING DUAL
       		ON (u.user_code = #{userCode})
    	WHEN MATCHED THEN
        	UPDATE SET 
            	u.group_id = #{groupId}
    	WHEN NOT MATCHED THEN
        	INSERT (
            		user_code
            		, group_id
        		    )
        	VALUES (
            		#{userCode}
            		, #{groupId}
        			)

mapper.update:
DECLARE
BEGIN
	UPDATE users
	SET group_id = NULL
	WHERE user_code = #{userCode};


		UPDATE users
		SET group_id = #{groupId}
		WHERE user_code = #{userCode};

END;

UPDATE users
SET group_id = NULL
WHERE login_id = #{userCode}
